import * as React from 'react';
import Button from '@mui/material/Button';
export default function ScrollDialog({ arrays }) {
  const { setPage, page, itemRarity, pos, pos0, pos1, pos2, itemImg, itemRecipe, pos0_epico, pos1_epico, pos2_epico, pos0_raro, pos1_raro, pos2_raro, pos0_incomum, pos1_incomum, pos2_incomum, assets1, assets2, assets3, assets4, assets5, assets6, pos0_lendario, pos1_lendario, pos2_lendario, } = arrays
  console.log(itemRarity)

  let pos0_lendario_result = 30;
  let pos1_lendario_result = 10;
  let pos2_lendario_result = 10;

  let pos0_epico_result = (pos0_lendario_result * 10) - pos0_epico;
  let pos1_epico_result = (pos1_lendario_result * 10) - pos1_epico;
  let pos2_epico_result = (pos2_lendario_result * 10) - pos2_epico;

  let pos2_raro_result = (pos2_epico_result * 10) - pos2_raro;
  let pos1_raro_result = (pos1_epico_result * 10) - pos1_raro;
  let pos0_raro_result = (pos0_epico_result * 10) - pos0_raro;

  let pos2_incomum_result = (pos2_raro_result * 10) - pos0_incomum;
  let pos1_incomum_result = (pos1_raro_result * 10) - pos1_incomum;
  let pos0_incomum_result = (pos0_raro_result * 10) - pos2_incomum;

  let copper_total = ((pos0_raro_result + pos1_raro_result + pos2_raro_result) * 2000) + ((pos0_epico_result + pos1_epico_result + pos2_epico_result) * 20000) + 800000;
  let ds_total = ((pos0_raro_result + pos1_raro_result + pos2_raro_result) * 1000) + ((pos0_epico_result + pos1_epico_result + pos2_epico_result) * 5000) + 100000
  let po_total = ((pos0_raro_result + pos1_raro_result + pos2_raro_result) * 2) + ((pos0_epico_result + pos1_epico_result + pos2_epico_result) * 25)


  if (itemRarity === 'lendario') {
    pos0_lendario_result = 300 - pos0_lendario;
    pos1_lendario_result = 100 - pos1_lendario;
    pos2_lendario_result = 100 - pos2_lendario;

    pos0_epico_result = (pos0_lendario_result * 10) - pos0_epico;
    pos1_epico_result = (pos1_lendario_result * 10) - pos1_epico;
    pos2_epico_result = (pos2_lendario_result * 10) - pos2_epico;

    pos2_raro_result = (pos2_epico_result * 10) - pos2_raro;
    pos1_raro_result = (pos1_epico_result * 10) - pos1_raro;
    pos0_raro_result = (pos0_epico_result * 10) - pos0_raro;

    pos2_incomum_result = (pos2_raro_result * 10) - pos0_incomum;
    pos1_incomum_result = (pos1_raro_result * 10) - pos1_incomum;
    pos0_incomum_result = (pos0_raro_result * 10) - pos2_incomum;

    copper_total = ((pos0_raro_result + pos1_raro_result + pos2_raro_result) * 2000) + ((pos0_epico_result + pos1_epico_result + pos2_epico_result) * 20000) + ((pos0_lendario_result + pos1_lendario_result + pos2_lendario_result) * 100000) + 10000000;
    ds_total = ((pos0_raro_result + pos1_raro_result + pos2_raro_result) * 1000) + ((pos0_epico_result + pos1_epico_result + pos2_epico_result) * 5000) + ((pos0_lendario_result + pos1_lendario_result + pos2_lendario_result) * 25000) + 1000000
    po_total = ((pos0_raro_result + pos1_raro_result + pos2_raro_result) * 2) + ((pos0_epico_result + pos1_epico_result + pos2_epico_result) * 25) + ((pos0_lendario_result + pos1_lendario_result + pos2_lendario_result) * 125)


  }

  function next() {
    setPage(page + 1);
  }
  function prev() {
    setPage(page - 1);
  }
  function home() {
    setPage(0)
  }


  function convert(value) {
    if (value >= 1000000) return Math.round(value / 1000000) + "M"
    if (value >= 1000) return Math.round(value / 1000) + "K";
    return value
  }
  function positivo(value) {
    return value >= 0 ? value : 0;
  }
  function max(current, max) {
    return `${current >= max ? max : current}/${max}`
  }
  return (
    <div>
      <center>
        <Button variant="outlined" onClick={prev}>Prev</Button>
        <Button variant="outlined" onClick={home}>Home</Button>
        <Button variant="outlined" disabled>Next</Button>
      </center>
      <div style={{ paddingTop: '10px', paddingRight: '10px', paddingLeft: '10px', display: 'grid', justifyContent: 'center' }}>
        <div style={{ display: 'flex', paddingBottom: '20px' }} className="grid-container">
          {itemRarity === 'lendario' && <div style={{ paddingTop: '10px', paddingRight: '10px', paddingLeft: '10px', display: 'grid', justifyContent: 'center' }} className="grid-container">
            <div className="grid-item"><img
              loading="lazy"
              width='60px'
              src={``}
              srcSet={``}
              alt=""
            />
            </div>
            <div className="grid-item lendario"><img
              loading="lazy"
              width='60px'
              src={`${itemImg}`}
              srcSet={`${itemImg}`}
              alt=""
            />{itemRecipe}
            </div>
          </div>
          }
        </div>

        <div className="grid-container">
          {itemRarity === 'lendario' && <div className="grid-container">
            <div className="grid-item lendario">
              <img
                loading="lazy"
                width="60px"
                src={`${pos0}`}
                srcSet={`${pos0}`}
                alt=""
              />{max(pos0_lendario, 300)}
            </div>

            <div className="grid-item lendario">
              <img
                loading="lazy"
                width="60px"
                src={`${pos1}`}
                srcSet={`${pos1}`}
                alt=""
              />{max(pos1_lendario, 100)}
            </div>

            <div className="grid-item lendario">
              <img
                loading="lazy"
                width="60px"
                src={`${pos2}`}
                srcSet={`${pos2}`}
                alt=""
              />{max(pos2_lendario, 100)}
            </div>

            <div className="grid-item lendario ">
              <img
                loading="lazy"
                width="60px"
                src={`${pos}`}
                srcSet={`${pos}`}
                alt=""
              />1/1
            </div>
          </div>
          }
        </div>
        {itemRarity === 'epico' && <div>
          <div style={{ display: 'flex', paddingBottom: '20px' }} className="grid-container">
            <div className="grid-item">
              <img
                loading="lazy"
                width='60px'
                src={``}
                srcSet={``}
                alt=""
              />
            </div>
            <div className="grid-item epico">
              <img
                loading="lazy"
                width='60px'
                src={`${itemImg}`}
                srcSet={`${itemImg}`}
                alt=""
              />{itemRecipe}
            </div>
          </div>
        </div>
        }
        <div className="grid-container">
          <div className="grid-item epico">
            <img
              loading="lazy"
              width="60px"
              src={`${pos0}`}
              srcSet={`${pos0}`}
              alt=""
            />{max(pos0_epico, (positivo(pos0_epico_result)))}
          </div>
          <div className="grid-item epico">
            <img
              loading="lazy"
              width="60px"
              src={`${pos1}`}
              srcSet={`${pos1}`}
              alt=""
            />{max(pos1_epico, (positivo(pos1_epico_result)))}
          </div>
          <div className="grid-item epico">
            <img
              loading="lazy"
              width="60px"
              src={`${pos2}`}
              srcSet={`${pos2}`}
              alt=""
            />{max(pos2_epico, (positivo(pos2_epico_result)))}
          </div>

          {itemRarity === 'epico' && <div className="grid-item epico ">
            <img
              loading="lazy"
              width="60px"
              src={`${pos}`}
              srcSet={`${pos}`}
              alt=""
            />1/1
          </div>
          }
        </div>
        <div className="grid-container">
          <div className="grid-item raro">
            <img
              loading="lazy"
              width="60px"
              src={`${pos0}`}
              srcSet={`${pos0}`}
              alt=""
            />{max(pos0_raro, (convert(positivo(pos0_raro_result))))}
          </div>
          <div className="grid-item raro">
            <img
              loading="lazy"
              width="60px"
              src={`${pos1}`}
              srcSet={`${pos1}`}
              alt=""
            />{max(pos1_raro, (convert(positivo(pos1_raro_result))))}
          </div>
          <div className="grid-item raro">
            <img
              loading="lazy"
              width="60px"
              src={`${pos2}`}
              srcSet={`${pos2}`}
              alt=""
            />{max(pos2_raro, (convert(positivo(pos2_raro_result))))}
          </div>

        </div>
        <div className="grid-container">
          <div className="grid-item incomum">
            <img
              loading="lazy"
              width="60px"
              src={`${pos0}`}
              srcSet={`${pos0}`}
              alt=""
            />{max(pos0_incomum, (convert(positivo(pos0_incomum_result))))}
          </div>
          <div className="grid-item incomum">
            <img
              loading="lazy"
              width="60px"
              src={`${pos1}`}
              srcSet={`${pos1}`}
              alt=""
            />{max(pos1_incomum, (convert(positivo(pos1_incomum_result))))}
          </div>
          <div className="grid-item incomum">
            <img
              loading="lazy"
              width="60px"
              src={`${pos2}`}
              srcSet={`${pos2}`}
              alt=""
            />
            {max(pos2_incomum, (convert(positivo(pos2_incomum_result))))}
          </div>
        </div>
      </div>
      <table>
        <tbody>
          <tr>
            <td className='table' style={{ display: 'inline-grid', justifyItems: 'center' }}><img src='data:image/webp;base64,' alt='' width='60px' />{convert(assets1)}/{convert(ds_total)}</td>
            <td className='table' style={{ display: 'inline-grid', justifyItems: 'center' }}><img src='data:image/webp;base64,' alt='' width='60px' />{convert(assets2)}/{convert(copper_total)}</td>
            <td className='table' style={{ display: 'inline-grid', justifyItems: 'center' }}><img src='https://file.mir4global.com/xdraco-thumb/Content/UI/Atlas_N_Resource/Icon/Item/Consume_01/Item_Production_Meterial01_TwinclePowder.png' alt='' width='60px' />{convert(assets3)}/{convert(po_total)}</td>
          </tr>
          { assets4 != 0 || assets5 != 0 || assets6 != 0 &&<>
          <tr>
            <td className='table' style={{ display: 'inline-grid', justifyItems: 'center' }}>{convert(positivo(((ds_total - assets1) / 1000000) * assets6))}</td>
            <td className='table' style={{ display: 'inline-grid', justifyItems: 'center' }}>{convert(positivo(((copper_total - assets2) / 10000) * assets4))}</td>
            <td className='table' style={{ display: 'inline-grid', justifyItems: 'center' }}>{convert(positivo(((po_total - assets3) * assets5)))}</td>
          </tr>
          <tr>
            <td className='table1' style={{ display: 'inline-grid', justifyItems: 'center' }}></td>
            <td className='table' style={{ display: 'inline-grid', justifyItems: 'center' }}><img src='https://i.imgur.com/ZhZN8rw.png' alt='' width='60px' />{convert(positivo((((copper_total - assets2) / 10000) * assets4) + (((ds_total - assets1) / 1000000) * assets6) + ((po_total - assets3) * assets5)))}</td>
            <td className='table1' style={{ display: 'inline-grid', justifyItems: 'center' }}></td>
          </tr>
          </>}
        </tbody>
      </table>

    </div>
  );
}
