import React from 'react';
import './App.css';
import Inputs from './components/inputs.js';
import { createTheme, ThemeProvider } from '@mui/material/styles';
import useMediaQuery from '@mui/material/useMediaQuery';
import img from '../src/1.png'
import { useState } from 'react';
function App() {
  const [page, setPage] = useState(0);
  const [value, setValue] = React.useState(0);
  function prev() {
    setPage(page - 1);
    console.log(page)
  }
  const prefersDarkMode = useMediaQuery('(prefers-color-scheme: dark)');
  const theme = React.useMemo(
    () =>
      createTheme({
        palette: {
          mode: prefersDarkMode ? 'dark' : 'dark'
        },
      }),
    [prefersDarkMode],
  );
  return (
    <div className="App">
      
      <ThemeProvider theme={theme}>
        <a href='/' style={{ color: 'white' }}><img src={img} /></a>
        <Inputs arrays={{ page, setPage }} />
        <footer className="page-footer">
          <span>Made with ❤️ by </span>
          <a href="https://jeffhinoto.herokuapp.com" target="_blank">
            Jeff Hinoto
            <img width="24" height="24" src="https://jeffhinoto.herokuapp.com/src/index.html/static/media/img.0fada9266777c0d9ca88.png" alt="" />
          </a>
        </footer>
      </ThemeProvider>
    </div>
  );
}

export default App;
